import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    private static final String BASE_DIRECTORY = "/var/www/html/";

    public static void main(String[] args) {
        String userInput = "../secretfile.txt"; // User input containing path traversal

        String sanitizedPath = Paths.get(BASE_DIRECTORY, userInput).normalize().toString();

        if (!sanitizedPath.startsWith(BASE_DIRECTORY)) {
            System.err.println("Invalid file path specified.");
            return;
        }

        try {
            File file = new File(sanitizedPath);
            FileInputStream fis = new FileInputStream(file);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } catch (IOException e) {
            System.err.println("Error accessing file: " + e.getMessage());
        }
    }
}

